fun solve(code: Array<String>, businessLine: Array<String>, isActive: Array<Boolean>): Array<String> {
    val businessOrder = mapOf("electronics" to 0, "grocery" to 1, "pharmacy" to 2, "restaurant" to 3)
    val valid = mutableListOf<Pair<String, String>>()
    for (i in 0 until code.size) {
        val c = code[i]
        val bl = businessLine[i]
        val a = isActive[i]
        if (c.isEmpty() || !businessOrder.containsKey(bl) || !a) {
            continue
        }
        if (Regex("^\\w+$").matches(c)) {
            valid.add(Pair(bl, c))
        }
    }
    valid.sortWith(compareBy<Pair<String, String>> { businessOrder[it.first]!! } { it.second })
    return valid.map { it.second }.toTypedArray()
}
